# Category: path_traversal

import os

def delete_user_file(filename, user_dir='uploads'):
    if not os.path.exists(user_dir):
        raise FileNotFoundError(f"Directory '{user_dir}' does not exist.")

    user_file_path = os.path.join(user_dir, filename)

    if not os.path.isfile(user_file_path):
        raise FileNotFoundError(f"File '{filename}' not found in directory '{user_dir}'.")

    if os.getuid() != 0:
        raise PermissionError("This script requires root privileges to delete files.")

    os.remove(user_file_path)